class Solution:
    def maxLen(self, n, edges, label):
        adj = [[] for _ in range(n)]
        for u, v in edges:
            adj[u].append(v)
            adj[v].append(u)
        best = 1 if n >= 1 else 0
        path = []
        def is_pal(seq):
            return seq == seq[::-1]
        visited = [False] * n
        def dfs(u):
            nonlocal best
            s = ''.join(label[x] for x in path)
            if is_pal(s):
                if len(s) > best:
                    best = len(s)
            for w in adj[u]:
                if not visited[w]:
                    visited[w] = True
                    path.append(w)
                    dfs(w)
                    path.pop()
                    visited[w] = False
        for start in range(n):
            visited[start] = True
            path.append(start)
            dfs(start)
            path.pop()
            visited[start] = False
        return best

