class Solution:
    def maxLen(self, n, edges, label):
        if n == 0:
            return 0
        adj = [[] for _ in range(n)]
        for u, v in edges:
            adj[u].append(v)
            adj[v].append(u)
        from collections import deque
        best = 1
        seen = set()
        dq = deque()
        for a in range(n):
            st = (a, a, 1 << a)
            seen.add(st)
            dq.append((a, a, 1 << a, 1))
        for a in range(n):
            for b in adj[a]:
                if a < b and label[a] == label[b]:
                    mask = (1 << a) | (1 << b)
                    st = (a, b, mask)
                    if st not in seen:
                        seen.add(st)
                        dq.append((a, b, mask, 2))
                        best = max(best, 2)
        while dq:
            u, v, mask, length = dq.popleft()
            if length > best:
                best = length
            for x in adj[u]:
                if mask & (1 << x):
                    continue
                for y in adj[v]:
                    if x == y or (mask & (1 << y)):
                        continue
                    if label[x] != label[y]:
                        continue
                    nmask = mask | (1 << x) | (1 << y)
                    nst = (x, y, nmask)
                    if nst not in seen:
                        seen.add(nst)
                        dq.append((x, y, nmask, length + 2))
        return best

