var maxLen = function(n, edges, label) {
    if (n === 0) return 0;
    const adj = Array.from({length: n}, () => []);
    for (const [u, v] of edges) { adj[u].push(v); adj[v].push(u); }
    let best = 1;
    const seen = new Set();
    const queue = [];
    const key = (a, b, m) => a + ',' + b + ',' + m;
    for (let a = 0; a < n; a++) {
        const m = 1 << a;
        seen.add(key(a, a, m));
        queue.push([a, a, m, 1]);
    }
    for (let a = 0; a < n; a++) {
        for (const b of adj[a]) {
            if (a < b && label[a] === label[b]) {
                const m = (1 << a) | (1 << b);
                const k = key(a, b, m);
                if (!seen.has(k)) { seen.add(k); queue.push([a, b, m, 2]); best = Math.max(best, 2); }
            }
        }
    }
    let head = 0;
    while (head < queue.length) {
        const [u, v, mask, length] = queue[head++];
        if (length > best) best = length;
        for (const x of adj[u]) {
            if (mask & (1 << x)) continue;
            for (const y of adj[v]) {
                if (x === y || (mask & (1 << y))) continue;
                if (label[x] !== label[y]) continue;
                const nmask = mask | (1 << x) | (1 << y);
                const k = key(x, y, nmask);
                if (!seen.has(k)) { seen.add(k); queue.push([x, y, nmask, length + 2]); }
            }
        }
    }
    return best;
};
